1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteInput = {
4	  customer: Customer;
5	  items: Item[];
6	  previousContracts: number;
7	};
8	
9	const PROCESSING_FEE = 5;
10	const NEWCOMER_PER_ITEM_SURCHARGE_RATE = 0.1;
11	const CURSED_SURCHARGE_RATE = 0.5;
12	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const COMPONENT_BLOCK_SIZE = 3;
15	const COMPONENT_BLOCK_BASE = 60;
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	
19	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	const basePremiumForItem = (item: Item): number =>
29	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
30	
31	const isNewcomer = (customer: Customer): boolean =>
32	  customer.yearsWithMHPCO === 0;
33	
34	const isHighlyEnchanted = (item: Item): boolean =>
35	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
36	
37	const isCursed = (item: Item): boolean => item.cursed === true;
38	
39	const surcharge = (base: number, applies: boolean, rate: number): number =>
40	  applies ? base * rate : 0;
41	
42	const premiumForItem = (item: Item, customer: Customer): number => {
43	  const base = basePremiumForItem(item);
44	  return (
45	    base +
46	    surcharge(base, isCursed(item), CURSED_SURCHARGE_RATE) +
47	    surcharge(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE) +
48	    surcharge(base, isNewcomer(customer), NEWCOMER_PER_ITEM_SURCHARGE_RATE)
49	  );
50	};
51	
52	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
53	
54	const componentGroupBase = (items: Item[]): number => {
55	  const blocks = Math.floor(items.length / COMPONENT_BLOCK_SIZE);
56	  const singles = items.length % COMPONENT_BLOCK_SIZE;
57	  const itemBase = basePremiumForItem(items[0]);
58	  return blocks * COMPONENT_BLOCK_BASE + singles * itemBase;
59	};
60	
61	const groupByType = (items: Item[]): Map<string, Item[]> => {
62	  const groups = new Map<string, Item[]>();
63	  for (const item of items) {
64	    const list = groups.get(item.type) ?? [];
65	    list.push(item);
66	    groups.set(item.type, list);
67	  }
68	  return groups;
69	};
70	
71	const componentsTotal = (items: Item[], customer: Customer): number => {
72	  const groups = groupByType(items);
73	  let total = 0;
74	  for (const groupItems of groups.values()) {
75	    const groupBase = componentGroupBase(groupItems);
76	    total +=
77	      groupBase +
78	      surcharge(
79	        groupBase,
80	        isNewcomer(customer),
81	        NEWCOMER_PER_ITEM_SURCHARGE_RATE,
82	      );
83	  }
84	  return total;
85	};
86	
87	export const quote = (input: QuoteInput): { premium: number } => {
88	  const components = input.items.filter(isComponent);
89	  const nonComponents = input.items.filter((item) => !isComponent(item));
90	  const nonComponentsTotal = nonComponents.reduce(
91	    (sum, item) => sum + premiumForItem(item, input.customer),
92	    0,
93	  );
94	  const itemsTotal =
95	    nonComponentsTotal + componentsTotal(components, input.customer);
96	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
97	};
98	
99	export const claim = (_input: unknown): unknown => {
100	  return undefined;
101	};
